#include <iostream>
#include <cmath>  // for abs()

using namespace std;

int main() {
    double trueValue, approxValue;
    double absoluteError, relativeError;

    cout << "Enter true value: ";
    cin >> trueValue;

    cout << "Enter approximate value: ";
    cin >> approxValue;

    absoluteError = abs(trueValue - approxValue);

    if (trueValue != 0) {
        relativeError = absoluteError / abs(trueValue);

        cout << "Absolute Error = " << absoluteError << endl;
        cout << "Relative Error = " << relativeError << endl;
    } else {
        cout << "Relative Error cannot be calculated (true value is 0)." << endl;
    }

    return 0;
}
